src/providers/fal.ts.source:
/**
 * @tryit/engine/providers/fal — fal.ai hosted try-on adapter.
 *
 * Maps a {@link TryOnRequest} to a fal model input, invokes the model via an injected
 * {@link FalRunner} (a narrow `subscribe` surface over @fal-ai/client), and maps the fal
 * output back into a validated {@link TryOnResult}. The runner is INJECTED so tests pass a
 * fake and no network is ever touched in unit tests. In production the runner is built lazily
 * from `FAL_KEY`; fail-closed — if the key is absent when the real client is first needed, the
 * provider throws rather than issuing an unauthenticated request, and the router falls through.
 */

import { createRequire } from 'node:module';
import type { TryOnRequest, TryOnResult } from '@tryit/contracts';
import type { ProviderContext, TryOnProvider } from '../provider.js';
import { imageRefToInput } from '../internal/image_ref_to_input.js';
import { validateProviderResult } from '../internal/validate_provider_result.js';

/** The fal endpoint this adapter targets. A virtual try-on model id on fal.ai. */
export const FAL_TRYON_ENDPOINT = 'fal-ai/cat-vton';

/** The minimal input shape sent to the fal model. Mapped from the request, no extra fields. */
export interface FalTryOnInput {
  readonly human_image_url: string;
  readonly garment_image_url: string;
  readonly seed?: number;
  readonly num_samples: number;
}

/** The minimal output shape this adapter reads back from a fal result's `data`. */
export interface FalTryOnOutput {
  readonly image?: { readonly url?: unknown } | undefined;
  readonly images?: ReadonlyArray<{ readonly url?: unknown }> | undefined;
}

/** A fal result envelope, mirroring @fal-ai/client's `Result<T>` minimally. */
export interface FalRunResult<T> {
  readonly data: T;
  readonly requestId: string;
}

/**
 * The narrow fal surface this adapter depends on: a single `subscribe` call. Injecting this
 * (rather than the full @fal-ai/client) keeps the seam tiny and trivially fakeable in tests.
 */
export interface FalRunner {
  subscribe(
    endpointId: string,
    options: { input: FalTryOnInput; abortSignal?: AbortSignal | undefined },
  ): Promise<FalRunResult<FalTryOnOutput>>;
}

/** Options controlling how the FalProvider resolves its runner and cost. */
export interface FalProviderOptions {
  /** Injected runner; when omitted the provider lazily builds the real client from FAL_KEY. */
  readonly runner?: FalRunner | undefined;
  /** Factory for the real runner, overridable in tests; defaults to the @fal-ai/client build. */
  readonly runnerFactory?: (() => FalRunner) | undefined;
  /** Cost attributed per successful call, surfaced on the result for budget accounting. */
  readonly costPerCallUsd?: number | undefined;
  /** Endpoint override; defaults to {@link FAL_TRYON_ENDPOINT}. */
  readonly endpoint?: string | undefined;
}

/** Resolve the person and garment image inputs from a request. */
function mapInput(req: TryOnRequest): FalTryOnInput {
  const human = imageRefToInput(req.personImage);
  // A request may carry an explicit garment image; otherwise the product id is the garment ref.
  const garmentRef = req.params?.garmentImage;
  const garment = garmentRef ? imageRefToInput(garmentRef) : `product:${req.productId}`;
  const input: FalTryOnInput = {
    human_image_url: human,
    garment_image_url: garment,
    num_samples: req.params?.numSamples ?? 1,
  };
  // exactOptionalPropertyTypes: only attach `seed` when actually provided.
  return req.params?.seed === undefined ? input : { ...input, seed: req.params.seed };
}

/** Extract the first usable https image URL from a fal output, or fail closed. */
function extractImageUrl(out: FalTryOnOutput): string {
  const single = out.image?.url;
  if (typeof single === 'string' && single.length > 0) {
    return single;
  }
  const first = out.images?.[0]?.url;
  if (typeof first === 'string' && first.length > 0) {
    return first;
  }
  // fail-closed: no image in the upstream payload is an error, not an empty success.
  throw new Error('fal: response contained no image url');
}

export class FalProvider implements TryOnProvider {
  public readonly id = 'fal' as const;
  private runner: FalRunner | undefined;
  private readonly runnerFactory: () => FalRunner;
  private readonly costPerCallUsd: number;
  private readonly endpoint: string;

  public constructor(options: FalProviderOptions = {}) {
    this.runner = options.runner;
    this.runnerFactory = options.runnerFactory ?? defaultFalRunnerFactory;
    this.costPerCallUsd = options.costPerCallUsd ?? 0;
    this.endpoint = options.endpoint ?? FAL_TRYON_ENDPOINT;
  }

  /** Lazily resolve the runner; building the real client fails closed without FAL_KEY. */
  private resolveRunner(): FalRunner {
    if (this.runner) {
      return this.runner;
    }
    this.runner = this.runnerFactory();
    return this.runner;
  }

  public async tryOn(req: TryOnRequest, ctx: ProviderContext): Promise<TryOnResult> {
    const input = mapInput(req);
    const runner = this.resolveRunner();
    ctx.logger.debug('fal.tryOn', { endpoint: this.endpoint, tenantId: req.tenantId });
    const result = await runner.subscribe(this.endpoint, {
      input,
      abortSignal: ctx.signal,
    });
    const url = extractImageUrl(result.data);
    // Re-validate the mapped result against the contract (https-only url, non-negative cost).
    return validateProviderResult(
      {
        resultImageUrl: url,
        provider: this.id,
        latencyMs: 0,
        cached: false,
        costUsd: this.costPerCallUsd,
      },
      'fal',
    );
  }
}

/**
 * Default factory for the real fal runner, built lazily from `FAL_KEY`.
 *
 * fail-closed: with no credential we refuse rather than issuing an unauthenticated request.
 * Kept out of the hot path and isolated so unit tests (which inject a runner) never load it.
 */
export function defaultFalRunnerFactory(): FalRunner {
  const key = process.env['FAL_KEY'];
  if (!key || key.length === 0) {
    throw new Error('fal: FAL_KEY is not configured');
  }
  // Lazy require keeps @fal-ai/client (CommonJS) off the unit-test path entirely; tests inject
  // a fake runner and never reach this branch. createRequire is the ESM-safe way to load it.
  const require = createRequire(import.meta.url);
  const mod = require('@fal-ai/client') as {
    createFalClient: (cfg: { credentials: string }) => FalRunner;
  };
  return mod.createFalClient({ credentials: key });
}

src/router_ordering.ts.source:
/**
 * @tryit/engine/router_ordering — deterministic candidate ordering for the router.
 *
 * Turns a tenant's `allowedProviders` allow-list into the concrete, ordered list of provider
 * candidates the router will try. Ordering is by lowest `costPerCallUsd` first, then lowest
 * `priority` value (higher precedence), then provider id as a stable final tiebreak so the order
 * is fully deterministic. Only providers that are both allow-listed AND have routing metadata
 * AND have a registered implementation become candidates — deny-by-default everywhere.
 */

import type { ProviderId } from '@tryit/contracts';
import type { TryOnProvider } from './provider.js';

/** Routing metadata for one provider, independent of its implementation. */
export interface ProviderRouting {
  /** Lower value = higher precedence after cost. */
  readonly priority: number;
  /** Non-negative per-call cost in USD, the primary ordering key. */
  readonly costPerCallUsd: number;
  /** Optional per-provider timeout (ms); the router falls back to its default when absent. */
  readonly timeoutMs?: number | undefined;
}

/** A resolved, ordered candidate: its id plus the routing metadata used to order it. */
export interface OrderedCandidate extends ProviderRouting {
  readonly id: ProviderId;
}

/**
 * Order the tenant's allowed providers into the sequence the router should attempt.
 *
 * @param allowedProviders The tenant allow-list (deny-by-default; only these are eligible).
 * @param routing Per-provider routing metadata; a provider absent here is not a candidate.
 * @param registry Registered implementations; a provider with no implementation is dropped.
 * @returns Candidates sorted by cost asc, then priority asc, then id asc. May be empty.
 */
export function orderCandidates(
  allowedProviders: ReadonlyArray<ProviderId>,
  routing: ReadonlyMap<ProviderId, ProviderRouting>,
  registry: ReadonlyMap<ProviderId, TryOnProvider>,
): OrderedCandidate[] {
  // Dedupe the allow-list so a repeated entry cannot duplicate a candidate.
  const seen = new Set<ProviderId>();
  const candidates: OrderedCandidate[] = [];
  for (const id of allowedProviders) {
    if (seen.has(id)) {
      continue;
    }
    seen.add(id);
    const meta = routing.get(id);
    // deny-by-default: skip providers without routing metadata or a registered implementation.
    if (!meta || !registry.has(id)) {
      continue;
    }
    candidates.push({ id, ...meta });
  }
  candidates.sort(compareCandidates);
  return candidates;
}

/** Total, deterministic ordering: cost asc, then priority asc, then id asc. */
function compareCandidates(a: OrderedCandidate, b: OrderedCandidate): number {
  if (a.costPerCallUsd !== b.costPerCallUsd) {
    return a.costPerCallUsd - b.costPerCallUsd;
  }
  if (a.priority !== b.priority) {
    return a.priority - b.priority;
  }
  // Stable final tiebreak so equal cost+priority never depends on input order.
  return a.id < b.id ? -1 : a.id > b.id ? 1 : 0;
}

src/router_timeout.ts.source:
/**
 * @tryit/engine/router_timeout — injectable per-attempt timeout + cancellation for the router.
 *
 * Wraps a single provider attempt so it races against a wall-clock deadline and an optional
 * caller cancellation signal. Both time and timer scheduling come from an injectable
 * {@link RouterClock}, and the {@link AbortController} is injected too, so tests drive the
 * timeout path deterministically with zero real timers and zero network. On timeout the
 * attempt's signal is aborted (so a well-behaved provider stops its I/O) and a typed timeout
 * error is thrown for the router to catch and fall through.
 */

/**
 * The clock surface the router depends on. `now()` measures latency; `setTimer`/`clearTimer`
 * schedule the deadline. The default binds to the real `Date`/`setTimeout`; tests inject a fake.
 */
export interface RouterClock {
  now(): number;
  setTimer(callback: () => void, ms: number): unknown;
  clearTimer(handle: unknown): void;
}

/** The production clock, bound to wall-clock time and the host timer functions. */
export const SYSTEM_CLOCK: RouterClock = {
  now: () => Date.now(),
  setTimer: (callback, ms) => setTimeout(callback, ms),
  clearTimer: (handle) => clearTimeout(handle as ReturnType<typeof setTimeout>),
};

/** Options controlling a single timed attempt. */
export interface RunWithTimeoutOptions {
  readonly timeoutMs: number;
  readonly clock: RouterClock;
  /** The injected controller whose signal is passed to the attempt and aborted on timeout. */
  readonly controller: AbortController;
  /** Optional caller cancellation; aborting it aborts the attempt too. */
  readonly callerSignal?: AbortSignal | undefined;
  /** Provider label used to make the timeout error actionable. */
  readonly providerLabel: string;
}

/** Error thrown when an attempt exceeds its deadline, distinguishable from provider errors. */
export class ProviderTimeoutError extends Error {
  public constructor(providerLabel: string, timeoutMs: number) {
    super(`${providerLabel}: timed out after ${timeoutMs}ms`);
    this.name = 'ProviderTimeoutError';
  }
}

/**
 * Run `attempt` with a deadline and cancellation, resolving with its value or rejecting with the
 * provider's error / a {@link ProviderTimeoutError}.
 *
 * The attempt receives the controller's {@link AbortSignal}; on timeout the controller is
 * aborted before the timeout error is raised so a cooperating provider can stop work.
 */
export function runWithTimeout<T>(
  attempt: (signal: AbortSignal) => Promise<T>,
  options: RunWithTimeoutOptions,
): Promise<T> {
  const { timeoutMs, clock, controller, callerSignal, providerLabel } = options;

  return new Promise<T>((resolve, reject) => {
    let settled = false;
    const finish = (fn: () => void): void => {
      if (settled) {
        return; // guard against a late timer/abort firing after the attempt already settled.
      }
      settled = true;
      clock.clearTimer(timer);
      if (callerSignal) {
        callerSignal.removeEventListener('abort', onCallerAbort);
      }
      fn();
    };

    const onCallerAbort = (): void => {
      // Propagate caller cancellation into the attempt, then reject this race.
      controller.abort();
      finish(() => reject(new Error(`${providerLabel}: cancelled by caller`)));
    };

    const timer = clock.setTimer(() => {
      // fail-closed on deadline: abort the attempt's signal, then reject with a timeout error.
      controller.abort();
      finish(() => reject(new ProviderTimeoutError(providerLabel, timeoutMs)));
    }, timeoutMs);

    if (callerSignal) {
      if (callerSignal.aborted) {
        onCallerAbort();
        return;
      }
      callerSignal.addEventListener('abort', onCallerAbort, { once: true });
    }

    // Kick off the attempt; its resolution/rejection wins the race if it beats the deadline.
    attempt(controller.signal).then(
      (value) => finish(() => resolve(value)),
      (error: unknown) => finish(() => reject(error)),
    );
  });
}

src/internal/image_ref_to_input.ts.source:
/**
 * @tryit/engine/internal/image_ref_to_input — normalise an ImageRef into a provider input URL.
 *
 * The hosted providers all accept an image as a single string — either the original HTTPS URL
 * or a `data:` URI for inline base64 bytes. This module performs that one mapping in a single
 * place so every adapter agrees on how a {@link TryOnRequest}'s person/garment image is encoded
 * for the wire, and so the https-only / allow-listed-MIME guarantees from the contract carry
 * straight through without each adapter re-implementing (and risking diverging on) the logic.
 */

import type { ImageRef } from '@tryit/contracts';

/**
 * Convert a validated {@link ImageRef} to the single-string form hosted providers expect.
 *
 * - `url` refs pass through their HTTPS URL unchanged (already https-validated by the contract).
 * - `base64` refs become a `data:<mime>;base64,<data>` URI from their allow-listed MIME type.
 *
 * The discriminated union is exhaustive; the unreachable branch fails closed.
 */
export function imageRefToInput(ref: ImageRef): string {
  if (ref.kind === 'url') {
    return ref.url;
  }
  if (ref.kind === 'base64') {
    return `data:${ref.mimeType};base64,${ref.data}`;
  }
  // fail-closed: an unknown discriminant (should be impossible post-validation) is rejected.
  throw new Error('imageRefToInput: unsupported image reference kind');
}

src/internal/validate_provider_result.ts.source:
/**
 * @tryit/engine/internal/validate_provider_result — re-validate untrusted upstream results.
 *
 * Provider adapters map external responses (fal, replicate, google, self-hosted) into a
 * {@link TryOnResult}. Those responses are untrusted I/O, so before any mapped result leaves a
 * provider it is parsed against the contract schema. This enforces, among other things, the
 * https-only result-URL invariant and non-negative latency/cost — fail-closed: a malformed
 * upstream payload is rejected (thrown) rather than surfaced to the caller.
 */

import { safeParseTryOnResult, type TryOnResult } from '@tryit/contracts';

/**
 * Validate a candidate result against the contract, throwing on any violation.
 *
 * @param candidate The provider-mapped result (untrusted shape).
 * @param providerLabel Used only to make the thrown error message actionable.
 * @returns The same value, now proven to satisfy {@link TryOnResult}.
 * @throws Error if the candidate does not satisfy the result contract.
 */
export function validateProviderResult(candidate: unknown, providerLabel: string): TryOnResult {
  const parsed = safeParseTryOnResult(candidate);
  if (!parsed.success) {
    // fail-closed: surface a typed failure so the router falls through rather than returning
    // a result that violates the wire contract (e.g. a non-https or http result URL).
    throw new Error(`${providerLabel}: malformed provider result — ${parsed.error.message}`);
  }
  return parsed.data;
}

src/providers/deterministic.ts.source:
/**
 * @tryit/engine/providers/deterministic — the always-available terminal fallback provider.
 *
 * This provider NEVER fails and NEVER touches the network or environment. It derives a stable
 * fingerprint from the request (see ../internal/stable_request_hash.ts) and returns a
 * reproducible placeholder result: a renderable `data:image/svg+xml;base64,...` URL carrying the
 * deterministic SVG inline (see ./deterministic_placeholder_svg.ts). Identical requests therefore
 * yield a byte-identical {@link TryOnResult}, and because the image is inline it renders in a
 * browser with no host to resolve. It is both the offline/CI default and the router's guaranteed
 * last resort, so the engine can always answer fail-closed without hard-erroring.
 */

import type { TryOnRequest, TryOnResult } from '@tryit/contracts';
import type { ProviderContext, TryOnProvider } from '../provider.js';
import { stableRequestHash } from '../internal/stable_request_hash.js';
import { buildPlaceholderImageDataUrl } from './deterministic_placeholder_svg.js';

/**
 * The terminal, offline, reproducible provider.
 *
 * `tryOn` ignores the context's network-oriented fields (there is no I/O) but still honours an
 * already-aborted signal by failing closed, so a caller that cancelled before invoking does not
 * receive a result it no longer wants. Cost is always zero — no external call is made.
 */
export class DeterministicProvider implements TryOnProvider {
  public readonly id = 'deterministic' as const;

  public async tryOn(req: TryOnRequest, ctx: ProviderContext): Promise<TryOnResult> {
    // fail-closed: if the caller already aborted, do not fabricate a result they cancelled.
    if (ctx.signal.aborted) {
      throw new Error('deterministic: request already aborted');
    }
    const digest = stableRequestHash(req);
    ctx.logger.debug('deterministic.tryOn', { digest, tenantId: req.tenantId });
    return {
      resultImageUrl: buildPlaceholderImageDataUrl(digest),
      provider: this.id,
      // latency/cost are set authoritatively by the router; locals here are the provider's
      // own view (offline => zero marginal cost, ~instant). The router overwrites latencyMs.
      latencyMs: 0,
      cached: false,
      costUsd: 0,
    };
  }
}

src/providers/deterministic_placeholder_.source:
/**
 * @tryit/engine/providers/deterministic_placeholder_svg — reproducible placeholder image.
 *
 * Builds a deterministic SVG composite from a request's stable hash and wraps it as a renderable
 * `data:image/svg+xml;base64,...` URL. The output is purely a function of the digest, so identical
 * requests yield a byte-identical image and data URL. The data URL is the visible artefact behind
 * the deterministic provider's result; it never touches the network (no fake host to resolve) and
 * pulls colours/shapes solely from the digest's hex nibbles.
 */

/** Derive two hex-driven accent colours from the digest so the swatch varies per request. */
function coloursFromDigest(digest: string): { primary: string; secondary: string } {
  // Slice fixed windows of the 16-char hex digest into 6-char CSS colours; pad defensively.
  const primary = `#${(digest.slice(0, 6) + '000000').slice(0, 6)}`;
  const secondary = `#${(digest.slice(6, 12) + '000000').slice(0, 6)}`;
  return { primary, secondary };
}

/**
 * Render the deterministic placeholder SVG for a digest.
 *
 * @returns A self-contained SVG document string. Same digest -> identical bytes, always.
 */
export function buildPlaceholderSvg(digest: string): string {
  const { primary, secondary } = coloursFromDigest(digest);
  // A fixed 512x640 portrait canvas (try-on aspect) with two digest-driven bands plus the
  // digest printed as a label so the placeholder is visually traceable to its request.
  return [
    '<svg xmlns="http://www.w3.org/2000/svg" width="512" height="640" viewBox="0 0 512 640">',
    `<rect width="512" height="640" fill="${primary}"/>`,
    `<rect y="320" width="512" height="320" fill="${secondary}"/>`,
    '<text x="256" y="600" font-family="monospace" font-size="20" fill="#ffffff" ' +
      `text-anchor="middle">tryit:${digest}</text>`,
    '</svg>',
  ].join('');
}

/** Base64-encode a UTF-8 string. Node's Buffer is always present in the runtime targets. */
function base64Utf8(input: string): string {
  return Buffer.from(input, 'utf-8').toString('base64');
}

/**
 * Wrap the deterministic placeholder SVG as a browser-renderable data URL.
 *
 * @returns A self-contained `data:image/svg+xml;base64,...` URL. Same digest -> identical bytes,
 *   always, and it satisfies the contract's result-image-URL invariant (a safe inline image data
 *   URL), so the offline/fallback result renders instead of pointing at a non-resolvable host.
 */
export function buildPlaceholderImageDataUrl(digest: string): string {
  return `data:image/svg+xml;base64,${base64Utf8(buildPlaceholderSvg(digest))}`;
}

