src/providers/self-hosted.ts.source:
/**
 * @tryit/engine/providers/self-hosted — adapter for the self-hosted inference-py service.
 *
 * POSTs a mapped {@link TryOnRequest} to the inference service's `/infer` endpoint over an
 * INJECTED `fetch`, then maps the JSON response into a validated {@link TryOnResult}. The fetch
 * is injected so unit tests provide a fixture responder and no network is touched. The call is
 * timeout-aware via the context's {@link AbortSignal}; a non-2xx status, a malformed body, or a
 * missing image URL all fail closed (throw) so the router falls through to the next provider.
 */

import type { TryOnRequest, TryOnResult } from '@tryit/contracts';
import type { ProviderContext, TryOnProvider } from '../provider.js';
import { imageRefToInput } from '../internal/image_ref_to_input.js';
import { validateProviderResult } from '../internal/validate_provider_result.js';

/** The minimal `fetch` surface the adapter needs, so any injected stub satisfies it. */
export type FetchLike = (
  input: string,
  init: {
    method: string;
    headers: Record<string, string>;
    body: string;
    signal?: AbortSignal | undefined;
  },
) => Promise<{
  ok: boolean;
  status: number;
  json(): Promise<unknown>;
}>;

/** Request body POSTed to the inference service. */
interface InferRequestBody {
  readonly person_image: string;
  readonly product_id: string;
  readonly category: string;
  readonly seed?: number;
  readonly num_samples: number;
}

/** Options for the self-hosted adapter. */
export interface SelfHostedProviderOptions {
  /** Base URL of the inference-py service, e.g. `https://infer.internal`. Required. */
  readonly baseUrl: string;
  /** Injected fetch implementation. Required so no global fetch is ever used implicitly. */
  readonly fetchImpl: FetchLike;
  /** Cost attributed per successful call. */
  readonly costPerCallUsd?: number | undefined;
}

/** Map the request into the inference service body. */
function mapBody(req: TryOnRequest): InferRequestBody {
  const base: InferRequestBody = {
    person_image: imageRefToInput(req.personImage),
    product_id: req.productId,
    category: req.category,
    num_samples: req.params?.numSamples ?? 1,
  };
  return req.params?.seed === undefined ? base : { ...base, seed: req.params.seed };
}

export class SelfHostedProvider implements TryOnProvider {
  public readonly id = 'self-hosted' as const;
  private readonly baseUrl: string;
  private readonly fetchImpl: FetchLike;
  private readonly costPerCallUsd: number;

  public constructor(options: SelfHostedProviderOptions) {
    // Strip a trailing slash so the joined path is well-formed regardless of caller input.
    this.baseUrl = options.baseUrl.replace(/\/+$/, '');
    this.fetchImpl = options.fetchImpl;
    this.costPerCallUsd = options.costPerCallUsd ?? 0;
  }

  public async tryOn(req: TryOnRequest, ctx: ProviderContext): Promise<TryOnResult> {
    const body = mapBody(req);
    ctx.logger.debug('selfHosted.tryOn', { baseUrl: this.baseUrl, tenantId: req.tenantId });
    const response = await this.fetchImpl(`${this.baseUrl}/infer`, {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify(body),
      signal: ctx.signal,
    });
    if (!response.ok) {
      // fail-closed: a non-2xx upstream status is a failure, not a degraded success.
      throw new Error(`self-hosted: inference service returned status ${response.status}`);
    }
    const payload = (await response.json()) as { image_url?: unknown };
    const url = payload.image_url;
    if (typeof url !== 'string' || url.length === 0) {
      throw new Error('self-hosted: response missing image_url');
    }
    return validateProviderResult(
      {
        resultImageUrl: url,
        provider: this.id,
        latencyMs: 0,
        cached: false,
        costUsd: this.costPerCallUsd,
      },
      'self-hosted',
    );
  }
}

src/router.ts.source:
/**
 * @tryit/engine/router — deterministic, fail-closed provider routing.
 *
 * Given a {@link TenantConfig} (its `allowedProviders` allow-list plus per-provider priority and
 * cost) the router orders candidate providers cheapest/highest-priority first, then tries each
 * in turn. On any error or per-call timeout it falls through to the next candidate, with the
 * {@link DeterministicProvider} as the guaranteed terminal fallback so the engine never hard
 * fails. The chosen result is stamped with the real provider id, measured `latencyMs`,
 * `cached: false`, and the provider's `costUsd`. Only if even the deterministic fallback is
 * excluded does the router return a typed {@link ApiError} (`PROVIDER_ERROR`) — fail-closed.
 *
 * All time and cancellation are injectable (clock + AbortController factory) so the timeout and
 * latency paths are fully deterministic and network-free under test.
 */

import {
  makeApiError,
  type ApiError,
  type ProviderConfig,
  type ProviderId,
  type TenantConfig,
  type TryOnRequest,
  type TryOnResult,
} from '@tryit/contracts';
import { type EngineLogger, NOOP_LOGGER, type TryOnProvider } from './provider.js';
import { orderCandidates, type ProviderRouting } from './router_ordering.js';
import { runWithTimeout, type RouterClock, SYSTEM_CLOCK } from './router_timeout.js';
import { validateProviderResult } from './internal/validate_provider_result.js';

/** A discriminated result: either a stamped {@link TryOnResult} or a typed {@link ApiError}. */
export type RouteOutcome =
  | { readonly ok: true; readonly result: TryOnResult }
  | { readonly ok: false; readonly error: ApiError };

/** Construction options for the router. */
export interface EngineRouterOptions {
  /** Per-provider routing metadata (priority + cost), keyed by provider id. */
  readonly routing: ReadonlyMap<ProviderId, ProviderRouting>;
  /** Default per-call timeout (ms) when a call does not specify one. Always >= 1. */
  readonly defaultTimeoutMs: number;
  /** Injectable clock for measuring latency and scheduling timeouts. Defaults to wall clock. */
  readonly clock?: RouterClock | undefined;
  /** Factory for the per-attempt AbortController; injectable for deterministic tests. */
  readonly abortControllerFactory?: (() => AbortController) | undefined;
  /** Structured logger; defaults to a no-op. */
  readonly logger?: EngineLogger | undefined;
}

/** Per-call overrides accepted by {@link EngineRouter.route}. */
export interface RouteOptions {
  /** Override the per-call timeout budget (ms). Falls back to the router default. */
  readonly timeoutMs?: number | undefined;
  /** Caller cancellation signal; when aborted, in-flight and pending attempts stop. */
  readonly signal?: AbortSignal | undefined;
}

/** Build a {@link ProviderRouting} map from an array of {@link ProviderConfig}. */
export function routingFromConfigs(
  configs: ReadonlyArray<ProviderConfig>,
): Map<ProviderId, ProviderRouting> {
  const map = new Map<ProviderId, ProviderRouting>();
  for (const config of configs) {
    if (!config.enabled) {
      continue; // disabled providers are never routing candidates.
    }
    map.set(config.id, {
      priority: config.priority,
      costPerCallUsd: config.costPerCallUsd,
      timeoutMs: config.timeoutMs,
    });
  }
  return map;
}

/**
 * The engine router. It owns a registry of provider implementations and the routing metadata,
 * and selects/falls-through per request against a tenant's policy.
 */
export class EngineRouter {
  private readonly registry: ReadonlyMap<ProviderId, TryOnProvider>;
  private readonly routing: ReadonlyMap<ProviderId, ProviderRouting>;
  private readonly defaultTimeoutMs: number;
  private readonly clock: RouterClock;
  private readonly abortControllerFactory: () => AbortController;
  private readonly logger: EngineLogger;

  public constructor(
    registry: ReadonlyMap<ProviderId, TryOnProvider>,
    options: EngineRouterOptions,
  ) {
    this.registry = registry;
    this.routing = options.routing;
    this.defaultTimeoutMs = options.defaultTimeoutMs;
    this.clock = options.clock ?? SYSTEM_CLOCK;
    this.abortControllerFactory = options.abortControllerFactory ?? (() => new AbortController());
    this.logger = options.logger ?? NOOP_LOGGER;
  }

  /**
   * Route a request through the tenant's allowed providers, cheapest/highest-priority first,
   * falling through on error/timeout and ending at the deterministic fallback.
   *
   * @returns `{ ok: true, result }` with the result stamped, or `{ ok: false, error }` with a
   *   `PROVIDER_ERROR` only when no candidate (not even deterministic) is permitted/usable.
   */
  public async route(
    req: TryOnRequest,
    tenant: TenantConfig,
    options: RouteOptions = {},
  ): Promise<RouteOutcome> {
    const candidates = orderCandidates(tenant.allowedProviders, this.routing, this.registry);
    if (candidates.length === 0) {
      // fail-closed: an empty allow-list (or no registered candidate) yields a typed error,
      // never a silent success. The deterministic fallback only applies when it is allow-listed.
      this.logger.warn('router.noCandidates', { tenantId: tenant.tenantId });
      return {
        ok: false,
        error: makeApiError('PROVIDER_ERROR', 'no provider is permitted for this tenant'),
      };
    }

    let lastError: unknown;
    for (const candidate of candidates) {
      // orderCandidates guarantees every candidate has a registered implementation, so the
      // non-null assertion is sound; deny-by-default filtering already dropped the rest.
      const provider = this.registry.get(candidate.id)!;
      const timeoutMs = this.resolveTimeout(candidate, options.timeoutMs);
      const started = this.clock.now();
      try {
        const result = await runWithTimeout(
          (signal) => provider.tryOn(req, { timeoutMs, signal, logger: this.logger }),
          {
            timeoutMs,
            clock: this.clock,
            callerSignal: options.signal,
            controller: this.abortControllerFactory(),
            providerLabel: candidate.id,
          },
        );
        const latencyMs = Math.max(0, this.clock.now() - started);
        // Stamp authoritative routing metadata over whatever the provider returned, then
        // re-validate at the router boundary (defence in depth): a provider that bypassed its
        // own validation and returned a contract-violating result (e.g. a non-https url) is
        // rejected here too and the router falls through rather than surfacing it. fail-closed.
        const stamped = validateProviderResult(
          {
            ...result,
            provider: candidate.id,
            latencyMs,
            cached: false,
            costUsd: candidate.costPerCallUsd,
          },
          `router:${candidate.id}`,
        );
        return { ok: true, result: stamped };
      } catch (error) {
        lastError = error;
        this.logger.warn('router.providerFailed', {
          provider: candidate.id,
          tenantId: tenant.tenantId,
          reason: error instanceof Error ? error.message : String(error),
        });
        // fall through to the next candidate.
      }
    }

    // Every candidate (including any deterministic fallback) failed.
    this.logger.error('router.allFailed', {
      tenantId: tenant.tenantId,
      reason: lastError instanceof Error ? lastError.message : String(lastError),
    });
    return {
      ok: false,
      error: makeApiError('PROVIDER_ERROR', 'all permitted providers failed'),
    };
  }

  /** Resolve the effective timeout: per-call override, else provider config, else default. */
  private resolveTimeout(candidate: ProviderRouting, callTimeoutMs: number | undefined): number {
    if (callTimeoutMs !== undefined) {
      return callTimeoutMs;
    }
    return candidate.timeoutMs ?? this.defaultTimeoutMs;
  }
}

src/provider.ts.source:
/**
 * @tryit/engine/provider — the TryOnProvider abstraction and its execution context.
 *
 * Every image backend (fal, replicate, google-vto, self-hosted, deterministic) implements
 * the same {@link TryOnProvider} interface so the router (see ./router.ts) can treat them
 * interchangeably and fall through from one to the next. A provider receives a validated
 * {@link TryOnRequest} plus a {@link ProviderContext} that carries the per-call deadline,
 * an {@link AbortSignal} for cooperative cancellation, and a structured logger. Providers
 * perform untrusted external I/O; their outputs are re-validated by the router before use.
 */

import type { ProviderId, TryOnRequest, TryOnResult } from '@tryit/contracts';

/**
 * A structured logger sink injected into providers so they never reach for a global
 * `console` (which would be unmockable and could leak into production logs untyped).
 * Implementations decide where the records go; the engine only emits structured events.
 */
export interface EngineLogger {
  debug(event: string, fields?: Record<string, unknown>): void;
  warn(event: string, fields?: Record<string, unknown>): void;
  error(event: string, fields?: Record<string, unknown>): void;
}

/** A no-op logger used as the safe default so a missing logger never throws. */
export const NOOP_LOGGER: EngineLogger = {
  debug: () => undefined,
  warn: () => undefined,
  error: () => undefined,
};

/**
 * Per-call execution context handed to a provider on each {@link TryOnProvider.tryOn}.
 *
 * `timeoutMs` is the wall-clock budget the caller allows for this attempt; `signal` is
 * aborted when that budget is exceeded (or the caller cancels) so providers doing real I/O
 * can bail early. `logger` is a structured sink. The context is read-only to the provider.
 */
export interface ProviderContext {
  /** Wall-clock budget for this single attempt, in milliseconds. Always >= 1. */
  readonly timeoutMs: number;
  /** Abort signal fired when the deadline is hit or the caller cancels. */
  readonly signal: AbortSignal;
  /** Structured logger; defaults to {@link NOOP_LOGGER} when the caller supplies none. */
  readonly logger: EngineLogger;
}

/**
 * A virtual try-on backend. Implementations map a {@link TryOnRequest} to a
 * {@link TryOnResult}, performing whatever external work they need within the
 * {@link ProviderContext} budget. They must reject (throw) on failure rather than
 * returning a partial/invalid result — the router treats a thrown error as a signal
 * to fall through to the next candidate.
 */
export interface TryOnProvider {
  /** The provider's stable identity, used by the router for ordering and accounting. */
  readonly id: ProviderId;
  /**
   * Produce a try-on result for `req` within `ctx`'s budget.
   *
   * @throws on any failure (network, timeout, malformed upstream response). The router
   *   catches and falls through; providers must not swallow errors into a fake success.
   */
  tryOn(req: TryOnRequest, ctx: ProviderContext): Promise<TryOnResult>;
}

src/router.test.ts.source:
/**
 * Tests for the EngineRouter (the engine's teeth): cost/priority selection, fall-through on
 * error and on timeout ending at the deterministic terminal fallback, authoritative stamping of
 * provider/latency/cached/cost, fail-closed PROVIDER_ERROR when no candidate is permitted or all
 * fail, per-call timeout override, and routingFromConfigs filtering. FakeClock + FakeProvider;
 * no real time, no network.
 */

import { describe, expect, it } from 'vitest';
import type { ProviderId } from '@tryit/contracts';
import { EngineRouter, routingFromConfigs } from './router.js';
import type { ProviderRouting } from './router_ordering.js';
import type { TryOnProvider } from './provider.js';
import { DeterministicProvider } from './providers/deterministic.js';
import {
  FakeClock,
  FakeProvider,
  makeRequest,
  makeResult,
  makeTenant,
} from './test_support/fixtures.js';

/** Assemble a registry from providers keyed by their id. */
function registryOf(...providers: TryOnProvider[]): Map<ProviderId, TryOnProvider> {
  return new Map(providers.map((p) => [p.id, p]));
}

const ROUTING_FAST: ProviderRouting = { priority: 1, costPerCallUsd: 0.05, timeoutMs: 100 };

describe('EngineRouter', () => {
  it('picks the cheapest permitted provider and stamps result metadata', async () => {
    const clock = new FakeClock();
    const fal = new FakeProvider('fal', { kind: 'resolve', result: makeResult({ provider: 'x' }) });
    const replicate = new FakeProvider('replicate', {
      kind: 'resolve',
      result: makeResult({ provider: 'y' }),
    });
    const router = new EngineRouter(registryOf(fal, replicate), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.05, timeoutMs: 100 }],
        ['replicate', { priority: 1, costPerCallUsd: 0.02, timeoutMs: 100 }],
      ]),
      defaultTimeoutMs: 100,
      clock,
    });

    const outcome = await router.route(
      makeRequest(),
      makeTenant({ allowedProviders: ['fal', 'replicate'] }),
    );

    expect(outcome.ok).toBe(true);
    if (outcome.ok) {
      // replicate is cheaper (0.02 < 0.05): it must be chosen and the id/cost stamped over it.
      expect(outcome.result.provider).toBe('replicate');
      expect(outcome.result.costUsd).toBe(0.02);
      expect(outcome.result.cached).toBe(false);
    }
    expect(replicate.calls).toBe(1);
    expect(fal.calls).toBe(0); // cheaper provider succeeded; no fall-through.
  });

  it('falls through a throwing provider to the next, then to deterministic', async () => {
    const clock = new FakeClock();
    const fal = new FakeProvider('fal', { kind: 'reject', error: new Error('fal down') });
    const replicate = new FakeProvider('replicate', {
      kind: 'reject',
      error: new Error('replicate down'),
    });
    const deterministic = new DeterministicProvider();
    const router = new EngineRouter(registryOf(fal, replicate, deterministic), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.01, timeoutMs: 100 }],
        ['replicate', { priority: 1, costPerCallUsd: 0.02, timeoutMs: 100 }],
        ['deterministic', { priority: 9, costPerCallUsd: 0, timeoutMs: 100 }],
      ]),
      defaultTimeoutMs: 100,
      clock,
    });

    const outcome = await router.route(
      makeRequest(),
      makeTenant({ allowedProviders: ['fal', 'replicate', 'deterministic'] }),
    );

    expect(outcome.ok).toBe(true);
    if (outcome.ok) {
      expect(outcome.result.provider).toBe('deterministic');
    }
    // Cheapest-first: deterministic (0) is tried FIRST and succeeds, so the others never run.
    expect(fal.calls).toBe(0);
    expect(replicate.calls).toBe(0);
  });

  it('tries the cheaper paid provider, then on error reaches deterministic fallback', async () => {
    const clock = new FakeClock();
    const fal = new FakeProvider('fal', { kind: 'reject', error: new Error('fal down') });
    const deterministic = new DeterministicProvider();
    const router = new EngineRouter(registryOf(fal, deterministic), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.05, timeoutMs: 100 }],
        ['deterministic', { priority: 9, costPerCallUsd: 0.5, timeoutMs: 100 }],
      ]),
      defaultTimeoutMs: 100,
      clock,
    });

    const outcome = await router.route(
      makeRequest(),
      makeTenant({ allowedProviders: ['fal', 'deterministic'] }),
    );

    // fal is cheaper here (0.05 < 0.5) so it's tried first, throws, then deterministic wins.
    expect(fal.calls).toBe(1);
    expect(outcome.ok && outcome.result.provider).toBe('deterministic');
    expect(outcome.ok && outcome.result.costUsd).toBe(0.5); // stamped from routing.
  });

  it('falls through a timing-out provider to the deterministic fallback', async () => {
    const clock = new FakeClock();
    const fal = new FakeProvider('fal', { kind: 'hang' });
    const deterministic = new DeterministicProvider();
    const router = new EngineRouter(registryOf(fal, deterministic), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.05, timeoutMs: 50 }],
        ['deterministic', { priority: 9, costPerCallUsd: 0.99, timeoutMs: 50 }],
      ]),
      defaultTimeoutMs: 50,
      clock,
    });

    const promise = router.route(
      makeRequest(),
      makeTenant({ allowedProviders: ['fal', 'deterministic'] }),
    );
    // Let the hanging fal attempt register its timer, then cross its deadline.
    await Promise.resolve();
    clock.advance(50);
    const outcome = await promise;

    expect(fal.calls).toBe(1);
    expect(outcome.ok && outcome.result.provider).toBe('deterministic');
  });

  it('records a non-negative measured latency stamped over the provider value', async () => {
    const clock = new FakeClock();
    // A provider that advances the clock while it runs, so latency is observable.
    const slow: TryOnProvider = {
      id: 'fal',
      async tryOn() {
        clock.advance(7);
        return makeResult({ latencyMs: 9999 });
      },
    };
    const router = new EngineRouter(registryOf(slow), {
      routing: new Map<ProviderId, ProviderRouting>([['fal', ROUTING_FAST]]),
      defaultTimeoutMs: 100,
      clock,
    });
    const outcome = await router.route(makeRequest(), makeTenant({ allowedProviders: ['fal'] }));
    expect(outcome.ok && outcome.result.latencyMs).toBe(7); // measured, not the provider's 9999.
  });

  it('returns PROVIDER_ERROR when the tenant allow-list permits nothing', async () => {
    const router = new EngineRouter(registryOf(new DeterministicProvider()), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['deterministic', { priority: 9, costPerCallUsd: 0 }],
      ]),
      defaultTimeoutMs: 100,
      clock: new FakeClock(),
    });
    const outcome = await router.route(makeRequest(), makeTenant({ allowedProviders: [] }));
    expect(outcome.ok).toBe(false);
    if (!outcome.ok) {
      expect(outcome.error.code).toBe('PROVIDER_ERROR');
      expect(outcome.error.httpStatus).toBe(502);
    }
  });

  it('returns PROVIDER_ERROR when every permitted provider fails (no deterministic allowed)', async () => {
    const fal = new FakeProvider('fal', { kind: 'reject', error: new Error('down') });
    const router = new EngineRouter(registryOf(fal, new DeterministicProvider()), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.05, timeoutMs: 100 }],
        ['deterministic', { priority: 9, costPerCallUsd: 0 }],
      ]),
      defaultTimeoutMs: 100,
      clock: new FakeClock(),
    });
    // deterministic NOT allow-listed, so the only candidate (fal) fails -> typed error.
    const outcome = await router.route(makeRequest(), makeTenant({ allowedProviders: ['fal'] }));
    expect(outcome.ok).toBe(false);
    expect(!outcome.ok && outcome.error.code).toBe('PROVIDER_ERROR');
    expect(fal.calls).toBe(1);
  });

  it('honours a per-call timeout override regardless of provider config', async () => {
    const clock = new FakeClock();
    const fal = new FakeProvider('fal', { kind: 'hang' });
    const deterministic = new DeterministicProvider();
    const router = new EngineRouter(registryOf(fal, deterministic), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.05, timeoutMs: 100000 }],
        ['deterministic', { priority: 9, costPerCallUsd: 0.99 }],
      ]),
      defaultTimeoutMs: 100000,
      clock,
    });
    const promise = router.route(
      makeRequest(),
      makeTenant({ allowedProviders: ['fal', 'deterministic'] }),
      { timeoutMs: 10 },
    );
    await Promise.resolve();
    clock.advance(10); // the override (10ms), not the 100000ms config, governs the deadline.
    const outcome = await promise;
    expect(outcome.ok && outcome.result.provider).toBe('deterministic');
  });

  it('rejects a provider returning a malformed result and falls through (defence in depth)', async () => {
    const clock = new FakeClock();
    // A registered provider that bypasses its own validation and returns a contract-violating
    // result (an insecure http url). The router must reject it at its boundary and fall through.
    const bad: TryOnProvider = {
      id: 'fal',
      async tryOn() {
        return { ...makeResult(), resultImageUrl: 'http://insecure/r.png' };
      },
    };
    const deterministic = new DeterministicProvider();
    const router = new EngineRouter(registryOf(bad, deterministic), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.05, timeoutMs: 100 }],
        ['deterministic', { priority: 9, costPerCallUsd: 0.99, timeoutMs: 100 }],
      ]),
      defaultTimeoutMs: 100,
      clock,
    });
    // fal (0.05) is cheaper than deterministic (0.99) -> tried first, its http url is rejected
    // by the router's post-stamp validation, then deterministic (renderable inline data url) wins
    // the fall-through.
    const outcome = await router.route(
      makeRequest(),
      makeTenant({ allowedProviders: ['fal', 'deterministic'] }),
    );
    expect(outcome.ok).toBe(true);
    if (outcome.ok) {
      expect(outcome.result.provider).toBe('deterministic');
      expect(outcome.result.resultImageUrl.startsWith('data:image/svg+xml;base64,')).toBe(true);
    }
  });

  it('routingFromConfigs drops disabled providers and maps fields', () => {
    const routing = routingFromConfigs([
      {
        id: 'fal',
        enabled: true,
        priority: 2,
        costPerCallUsd: 0.05,
        timeoutMs: 1234,
        maxConcurrency: 4,
      },
      {
        id: 'replicate',
        enabled: false,
        priority: 1,
        costPerCallUsd: 0.01,
        timeoutMs: 1000,
        maxConcurrency: 4,
      },
    ]);
    expect(routing.has('replicate')).toBe(false); // disabled => excluded.
    expect(routing.get('fal')).toEqual({ priority: 2, costPerCallUsd: 0.05, timeoutMs: 1234 });
  });
});

