/**
 * Tests for the fal adapter with a FAKE runner (no network). Asserts: request mapping shape
 * (human/garment/seed/num_samples, endpoint), abort signal forwarding, both `image` and
 * `images[]` output shapes, fail-closed on empty output and on a non-https url, and that the
 * default real-runner factory fails closed without FAL_KEY (and never runs in these tests).
 */

import { describe, expect, it, vi } from 'vitest';
import {
  FalProvider,
  FAL_TRYON_ENDPOINT,
  defaultFalRunnerFactory,
  type FalRunner,
  type FalTryOnInput,
  type FalTryOnOutput,
} from './fal.js';
import { makeContext, makeRequest } from '../test_support/fixtures.js';

/** A fake runner capturing its inputs and returning a scripted output. No network. */
function fakeRunner(
  output: FalTryOnOutput,
): FalRunner & { last?: { endpoint: string; input: FalTryOnInput; signal?: AbortSignal } } {
  const runner: FalRunner & {
    last?: { endpoint: string; input: FalTryOnInput; signal?: AbortSignal };
  } = {
    async subscribe(endpointId, options) {
      runner.last = {
        endpoint: endpointId,
        input: options.input,
        ...(options.abortSignal ? { signal: options.abortSignal } : {}),
      };
      return { data: output, requestId: 'req-1' };
    },
  };
  return runner;
}

describe('FalProvider', () => {
  it('maps person/garment/seed/num_samples and targets the try-on endpoint', async () => {
    const runner = fakeRunner({ image: { url: 'https://cdn.fal.ai/out.png' } });
    const provider = new FalProvider({ runner, costPerCallUsd: 0.05 });
    const req = makeRequest({
      personImage: { kind: 'url', url: 'https://cdn.example.com/person.jpg' },
      params: {
        seed: 7,
        numSamples: 3,
        garmentImage: { kind: 'base64', mimeType: 'image/png', data: 'QUJD' },
      },
    });

    const result = await provider.tryOn(req, makeContext());

    expect(runner.last?.endpoint).toBe(FAL_TRYON_ENDPOINT);
    expect(runner.last?.input).toEqual({
      human_image_url: 'https://cdn.example.com/person.jpg',
      garment_image_url: 'data:image/png;base64,QUJD',
      seed: 7,
      num_samples: 3,
    });
    expect(result.resultImageUrl).toBe('https://cdn.fal.ai/out.png');
    expect(result.provider).toBe('fal');
    expect(result.costUsd).toBe(0.05);
  });

  it('defaults num_samples to 1 and resolves garment from productId when none supplied', async () => {
    const runner = fakeRunner({ image: { url: 'https://cdn.fal.ai/out.png' } });
    const provider = new FalProvider({ runner });
    await provider.tryOn(makeRequest({ productId: 'sku-9' }), makeContext());
    expect(runner.last?.input).toEqual({
      human_image_url: 'https://cdn.example.com/person.jpg',
      garment_image_url: 'product:sku-9',
      num_samples: 1,
    });
    // exactOptionalPropertyTypes: no `seed` key should be present when none was provided.
    expect('seed' in (runner.last?.input ?? {})).toBe(false);
  });

  it('forwards the context abort signal to the runner', async () => {
    const runner = fakeRunner({ image: { url: 'https://cdn.fal.ai/out.png' } });
    const provider = new FalProvider({ runner });
    const ctx = makeContext();
    await provider.tryOn(makeRequest(), ctx);
    expect(runner.last?.signal).toBe(ctx.signal);
  });

  it('reads the first url from an images[] array output', async () => {
    const runner = fakeRunner({
      images: [{ url: 'https://cdn.fal.ai/first.png' }, { url: 'https://cdn.fal.ai/second.png' }],
    });
    const result = await new FalProvider({ runner }).tryOn(makeRequest(), makeContext());
    expect(result.resultImageUrl).toBe('https://cdn.fal.ai/first.png');
  });

  it('fails closed when the output carries no image url', async () => {
    const runner = fakeRunner({});
    await expect(
      new FalProvider({ runner }).tryOn(makeRequest(), makeContext()),
    ).rejects.toThrow(/no image url/);
  });

  it('fails closed when the upstream url is not https', async () => {
    const runner = fakeRunner({ image: { url: 'http://cdn.fal.ai/out.png' } });
    await expect(
      new FalProvider({ runner }).tryOn(makeRequest(), makeContext()),
    ).rejects.toThrow(/malformed provider result/);
  });

  it('lazily builds the runner via the injected factory exactly once', async () => {
    const runner = fakeRunner({ image: { url: 'https://cdn.fal.ai/out.png' } });
    const factory = vi.fn(() => runner);
    const provider = new FalProvider({ runnerFactory: factory });
    await provider.tryOn(makeRequest(), makeContext());
    await provider.tryOn(makeRequest(), makeContext());
    expect(factory).toHaveBeenCalledTimes(1); // cached after first resolution.
  });

  it('default runner factory fails closed when FAL_KEY is absent', () => {
    const saved = process.env['FAL_KEY'];
    delete process.env['FAL_KEY'];
    try {
      expect(() => defaultFalRunnerFactory()).toThrow(/FAL_KEY is not configured/);
    } finally {
      if (saved !== undefined) {
        process.env['FAL_KEY'] = saved;
      }
    }
  });
});

src/router.mutation.test.ts.source:
/**
 * Mutation-hardening tests for the router's correctness-critical arithmetic and timeout resolution.
 *
 * Targets two survivors the existing suite missed:
 *  - router.ts:140 (`Math.max(0, this.clock.now() - started)`): a `-`->`+` mutant on the latency
 *    computation survived because no test pinned an EXACT non-zero latency. We drive a stepping
 *    clock and assert the precise elapsed value, so `+` (which yields a wrong large number) dies.
 *  - router.ts:183 (`candidate.timeoutMs ?? this.defaultTimeoutMs`): a `??`->`&&` mutant survived
 *    because no test proved the per-provider timeout is preferred over the default. We give the
 *    provider a SHORT timeout and a LONG default, then assert the short one fires.
 */
import { describe, expect, it } from 'vitest';
import type { ProviderId } from '@tryit/contracts';
import { EngineRouter } from './router.js';
import type { ProviderRouting } from './router_ordering.js';
import type { TryOnProvider } from './provider.js';
import type { RouterClock } from './router_timeout.js';
import { FakeClock, FakeProvider, makeRequest, makeResult, makeTenant } from './test_support/fixtures.js';

function registryOf(...providers: TryOnProvider[]): Map<ProviderId, TryOnProvider> {
  return new Map(providers.map((p) => [p.id, p]));
}

describe('EngineRouter — latency arithmetic (mutation-hardening)', () => {
  it('stamps latencyMs as (now - started), an exact positive elapsed value', async () => {
    // A clock that returns `started` on the first now() and started+250 on the second.
    let calls = 0;
    const STEP = 250;
    const clock: RouterClock = {
      now: () => (calls++ === 0 ? 1000 : 1000 + STEP),
      setTimer: () => 0,
      clearTimer: () => undefined,
    };
    const fal = new FakeProvider('fal', { kind: 'resolve', result: makeResult({ provider: 'x' }) });
    const router = new EngineRouter(registryOf(fal), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.05, timeoutMs: 100 }],
      ]),
      defaultTimeoutMs: 100,
      clock,
    });

    const outcome = await router.route(makeRequest(), makeTenant({ allowedProviders: ['fal'] }));
    expect(outcome.ok).toBe(true);
    if (outcome.ok) {
      // now - started = 250. A `+` mutant would yield 1000 + 1250 = 2250 (≠ 250). Exact-kill.
      expect(outcome.result.latencyMs).toBe(STEP);
    }
  });
});

describe('EngineRouter — per-provider timeout preferred over default (mutation-hardening)', () => {
  it('uses the candidate.timeoutMs (short) and times out before the long default would', async () => {
    const clock = new FakeClock();
    // A provider that hangs forever: only a timeout can end the attempt.
    const hanging = new FakeProvider('fal', { kind: 'hang' });
    const router = new EngineRouter(registryOf(hanging), {
      routing: new Map<ProviderId, ProviderRouting>([
        // SHORT per-provider timeout; LONG default. `??` must pick 50; `&&` would pick the default.
        ['fal', { priority: 1, costPerCallUsd: 0.05, timeoutMs: 50 }],
      ]),
      defaultTimeoutMs: 100_000,
      clock,
    });

    const outcome = router.route(makeRequest(), makeTenant({ allowedProviders: ['fal'] }));
    // Advance past the SHORT 50ms deadline but well short of the long default.
    clock.advance(50);
    const resolved = await outcome;
    // The only candidate hung and was timed out, so the router reports a fail-closed error.
    expect(resolved.ok).toBe(false);
    if (!resolved.ok) {
      expect(resolved.error.code).toBe('PROVIDER_ERROR');
    }
    expect(hanging.calls).toBe(1);
  });

  it('does NOT time out at the short deadline when default is short and used (control)', async () => {
    // Control: with no per-provider timeout, the default governs. Advancing only 50ms must NOT
    // fire a 100ms default deadline — proving the 50ms kill above came from candidate.timeoutMs.
    const clock = new FakeClock();
    const hanging = new FakeProvider('fal', { kind: 'hang' });
    const router = new EngineRouter(registryOf(hanging), {
      routing: new Map<ProviderId, ProviderRouting>([
        ['fal', { priority: 1, costPerCallUsd: 0.05 }],
      ]),
      defaultTimeoutMs: 100,
      clock,
    });
    let settled = false;
    const p = router.route(makeRequest(), makeTenant({ allowedProviders: ['fal'] })).then((o) => {
      settled = true;
      return o;
    });
    clock.advance(50); // before the 100ms default deadline
    await Promise.resolve();
    expect(settled).toBe(false); // still pending — default timeout has not fired
    clock.advance(50); // now at 100ms — default deadline fires
    await p;
    expect(settled).toBe(true);
  });
});

src/providers/deterministic.test.ts.source:
/**
 * Tests for the deterministic provider: reproducibility (byte-identical for identical input),
 * full offline operation, a renderable data:image/svg+xml contract-valid output, sensitivity to
 * request changes, and fail-closed on an already-aborted context. Property-based with fast-check;
 * no network.
 */

import { describe, expect, it } from 'vitest';
import fc from 'fast-check';
import { safeParseTryOnResult, type TryOnRequest } from '@tryit/contracts';
import { DeterministicProvider } from './deterministic.js';
import { makeContext, makeRequest } from '../test_support/fixtures.js';

/** The exact data-URL prefix every deterministic result must carry (renderable inline SVG). */
const DATA_URL_PREFIX = 'data:image/svg+xml;base64,';

/** Arbitrary that produces a structurally-valid, varied TryOnRequest. */
const requestArb: fc.Arbitrary<TryOnRequest> = fc
  .record({
    tenantId: fc.string({ minLength: 1, maxLength: 20 }),
    shopperId: fc.string({ minLength: 1, maxLength: 20 }),
    productId: fc.string({ minLength: 1, maxLength: 20 }),
    url: fc.webUrl().filter((u) => u.startsWith('https://')),
    seed: fc.option(fc.integer(), { nil: undefined }),
  })
  .map(({ tenantId, shopperId, productId, url, seed }) => {
    const base: TryOnRequest = {
      tenantId,
      shopperId,
      productId,
      personImage: { kind: 'url', url },
      category: 'apparel',
    };
    return seed === undefined ? base : { ...base, params: { seed } };
  });

describe('DeterministicProvider', () => {
  const provider = new DeterministicProvider();

  it('produces a byte-identical result for the identical request (property)', async () => {
    await fc.assert(
      fc.asyncProperty(requestArb, async (req) => {
        const a = await provider.tryOn(req, makeContext());
        const b = await provider.tryOn(req, makeContext());
        // Reproducibility: every field, including the full result URL, must match exactly.
        expect(b.resultImageUrl).toBe(a.resultImageUrl);
        expect(JSON.stringify(b)).toBe(JSON.stringify(a));
      }),
      { numRuns: 200 },
    );
  });

  it('produces distinct URLs for requests differing only in productId (property)', async () => {
    await fc.assert(
      fc.asyncProperty(
        fc.string({ minLength: 1, maxLength: 12 }),
        fc.string({ minLength: 1, maxLength: 12 }),
        async (p1, p2) => {
          fc.pre(p1 !== p2);
          const r1 = await provider.tryOn(makeRequest({ productId: p1 }), makeContext());
          const r2 = await provider.tryOn(makeRequest({ productId: p2 }), makeContext());
          expect(r1.resultImageUrl).not.toBe(r2.resultImageUrl);
        },
      ),
      { numRuns: 100 },
    );
  });

  it('returns a contract-valid result with the deterministic provider id and zero cost', async () => {
    const result = await provider.tryOn(makeRequest(), makeContext());
    const parsed = safeParseTryOnResult(result);
    expect(parsed.success).toBe(true);
    expect(result.provider).toBe('deterministic');
    expect(result.costUsd).toBe(0);
    expect(result.cached).toBe(false);
  });

  it('emits a renderable data:image/svg+xml base64 url that satisfies the result contract', async () => {
    const result = await provider.tryOn(makeRequest(), makeContext());
    // The result must be an inline, browser-renderable image — not a non-resolvable fake host.
    expect(result.resultImageUrl.startsWith(DATA_URL_PREFIX)).toBe(true);
    // And it must PASS the contract's TryOnResultSchema (the router re-validates the same way).
    expect(safeParseTryOnResult(result).success).toBe(true);
  });

  it('embeds the deterministic SVG inline as the base64 payload (offline, self-contained)', async () => {
    const result = await provider.tryOn(makeRequest(), makeContext());
    const b64 = result.resultImageUrl.slice(DATA_URL_PREFIX.length);
    const decoded = Buffer.from(b64, 'base64').toString('utf-8');
    expect(decoded.startsWith('<svg')).toBe(true);
    expect(decoded).toContain('viewBox="0 0 512 640"');
    expect(decoded).toContain('tryit:'); // the digest label is embedded -> traceable to its request.
  });

  it('fails closed when the context signal is already aborted', async () => {
    const controller = new AbortController();
    controller.abort();
    await expect(
      provider.tryOn(makeRequest(), makeContext({ signal: controller.signal })),
    ).rejects.toThrow(/already aborted/);
  });
});

src/router_ordering.test.ts.source:
/**
 * Tests for candidate ordering: cost-asc primary, priority-asc secondary, id-asc tiebreak;
 * deny-by-default for non-allow-listed, unregistered, or routing-less providers; dedupe of a
 * repeated allow-list entry; and a property that the order is a total, deterministic sort.
 */

import { describe, expect, it } from 'vitest';
import fc from 'fast-check';
import type { ProviderId } from '@tryit/contracts';
import { orderCandidates, type ProviderRouting } from './router_ordering.js';
import type { TryOnProvider } from './provider.js';

const ALL_IDS: ProviderId[] = ['fal', 'replicate', 'google-vto', 'self-hosted', 'deterministic'];

/** Minimal registry whose presence is all ordering cares about. */
function registry(ids: ProviderId[]): Map<ProviderId, TryOnProvider> {
  const map = new Map<ProviderId, TryOnProvider>();
  for (const id of ids) {
    map.set(id, { id, tryOn: async () => ({}) as never });
  }
  return map;
}

describe('orderCandidates', () => {
  it('orders by cost ascending, then priority ascending, then id', () => {
    const routing = new Map<ProviderId, ProviderRouting>([
      ['fal', { priority: 1, costPerCallUsd: 0.05 }],
      ['replicate', { priority: 1, costPerCallUsd: 0.02 }],
      ['self-hosted', { priority: 5, costPerCallUsd: 0.02 }],
      ['deterministic', { priority: 9, costPerCallUsd: 0 }],
    ]);
    const ordered = orderCandidates(
      ['fal', 'replicate', 'self-hosted', 'deterministic'],
      routing,
      registry(ALL_IDS),
    );
    // 0 (deterministic) < 0.02 (replicate prio1 < self-hosted prio5) < 0.05 (fal).
    expect(ordered.map((c) => c.id)).toEqual(['deterministic', 'replicate', 'self-hosted', 'fal']);
  });

  it('breaks an exact cost+priority tie by provider id ascending', () => {
    const routing = new Map<ProviderId, ProviderRouting>([
      ['replicate', { priority: 1, costPerCallUsd: 0.01 }],
      ['fal', { priority: 1, costPerCallUsd: 0.01 }],
    ]);
    const ordered = orderCandidates(['replicate', 'fal'], routing, registry(ALL_IDS));
    expect(ordered.map((c) => c.id)).toEqual(['fal', 'replicate']); // 'fal' < 'replicate'.
  });

  it('denies providers that are not allow-listed', () => {
    const routing = new Map<ProviderId, ProviderRouting>([
      ['fal', { priority: 1, costPerCallUsd: 0.05 }],
      ['replicate', { priority: 1, costPerCallUsd: 0.02 }],
    ]);
    const ordered = orderCandidates(['fal'], routing, registry(ALL_IDS));
    expect(ordered.map((c) => c.id)).toEqual(['fal']);
  });

  it('drops allow-listed providers with no routing metadata or no implementation', () => {
    const routing = new Map<ProviderId, ProviderRouting>([
      ['fal', { priority: 1, costPerCallUsd: 0.05 }],
      ['replicate', { priority: 1, costPerCallUsd: 0.02 }],
    ]);
    // 'replicate' has routing but no registered impl; 'google-vto' has impl but no routing.
    const ordered = orderCandidates(
      ['fal', 'replicate', 'google-vto'],
      routing,
      registry(['fal', 'google-vto']),
    );
    expect(ordered.map((c) => c.id)).toEqual(['fal']);
  });

  it('dedupes a repeated allow-list entry', () => {
    const routing = new Map<ProviderId, ProviderRouting>([
      ['fal', { priority: 1, costPerCallUsd: 0.05 }],
    ]);
    const ordered = orderCandidates(['fal', 'fal', 'fal'], routing, registry(['fal']));
    expect(ordered).toHaveLength(1);
  });

  it('produces a total deterministic order regardless of allow-list ordering (property)', () => {
    const routing = new Map<ProviderId, ProviderRouting>(
      ALL_IDS.map((id, i) => [id, { priority: i % 3, costPerCallUsd: (i % 2) * 0.01 }]),
    );
    const reg = registry(ALL_IDS);
    fc.assert(
      fc.property(fc.shuffledSubarray(ALL_IDS, { minLength: ALL_IDS.length }), (shuffled) => {
        const a = orderCandidates(shuffled, routing, reg).map((c) => c.id);
        const b = orderCandidates([...ALL_IDS], routing, reg).map((c) => c.id);
        // Same set in, identical sorted order out — order is independent of input order.
        expect([...a].sort()).toEqual([...b].sort());
        expect(a).toEqual(b);
      }),
    );
  });
});

